"use client"

import React, { useEffect, useState } from "react";
import { Table, Badge } from "react-bootstrap";



export default function PaymentsTable() {

  const [payments, setPayments] = useState({
    id: "PAY12345",
    university: "",
    program: "",
    payDate: "2025-03-25",
    amount: "$5000",
    status: "false",
  });

  const [program, setProgram] = useState("")
  const [university, setUniversity] = useState("");
  const [status, setStatus]= useState(false);

  useEffect(() => {
      const university = localStorage.getItem("university_name");
      const program = localStorage.getItem("program_name");
      setProgram(program);
      const staus = localStorage.getItem("payment_completed");
      setUniversity(university);

      staus == "true" ? setStatus(true) : setStatus(false);
  }, [])


  return (
    <div className="container mt-4">
      <h3 className="mb-3">User Payments</h3>
      <Table striped bordered hover responsive>
        <thead className="table-danger">
          <tr>
            <th>Payment ID</th>
            <th>University</th>
            <th>Program</th>
            <th>Pay Date</th>
            <th>Paid Amount</th>
            <th>Status</th>
          </tr>
        </thead>
        <tbody>
          { payments && (
            <tr>
              <td>{payments.id}</td>
              <td>{university}</td>
              <td>{program}</td>
              <td>{payments.payDate}</td>
              <td>{payments.amount}</td>
              <td>
                <Badge
                  bg={
                    payments.status === "true"
                      ? "success"
                      : payments.status === "false"
                        ? "warning"
                        : "danger"
                  }
                >
                  {payments.status === "true" ? "Completed" : "Pending"}
                </Badge>
              </td>
            </tr>
          )
          }
        </tbody>
      </Table>
    </div>
  );
}
